:root {
  /* Color system (derived from design) */
  --color-bg: #030303; /* page background */
  --color-surface: #050509; /* header/footer surface */
  --color-surface-elevated: #0b0b10; /* cards on dark */

  --color-primary: #0052cc; /* key blue */
  --color-primary-bright: #0070ff;
  --color-primary-dark: #003366;

  --color-accent-yellow: #ffc400;
  --color-accent-red: #ff4b3a;
  --color-accent-red-strong: #ff3b30;
  --color-accent-green: #00c853;

  --color-neutral-100: #ffffff;
  --color-neutral-50: #f5f5f5;
  --color-neutral-400: #9ca3af;

  --color-border-subtle: #1f2933;

  /* Semantic colors */
  --color-success: #00c853;
  --color-error: #ff3b30;
  --color-warning: #ffc400;
  --color-info: #0052cc;

  /* Gradients approximating hero and promo card */
  --gradient-hero: radial-gradient(circle at 20% 0%, #0070ff 0%, #003366 35%, #030303 80%);
  --gradient-footer: radial-gradient(circle at 10% 0%, rgba(0, 112, 255, 0.4) 0%, transparent 45%),
                     radial-gradient(circle at 90% 0%, rgba(255, 75, 58, 0.35) 0%, transparent 50%),
                     #030303;

  /* Typography */
  --font-heading: 'Space Grotesk', 'Helvetica', sans-serif;
  --font-body: 'Source Sans 3', 'Arial', sans-serif;

  --font-size-h1: 32px;
  --font-size-h2: 26px;
  --font-size-h3: 20px;
  --font-size-body: 16px;
  --font-size-small: 13px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Radii */
  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 12px;
  --radius-pill: 999px;

  /* Shadows inspired by promo card/chat widget */
  --shadow-soft: 0 10px 25px rgba(0, 0, 0, 0.55);
  --shadow-strong: 0 24px 40px rgba(0, 0, 0, 0.75);

  /* Layout */
  --container-max-width: 1180px;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  min-height: 100vh;
  background-color: var(--color-bg);
  color: var(--color-neutral-100);
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:focus-visible,
button:focus-visible {
  outline: 2px solid var(--color-accent-yellow);
  outline-offset: 2px;
}

.site {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.site-content {
  flex: 1 0 auto;
}

/* Utility container to mimic centered promo layout */
.container {
  width: 100%;
  max-width: var(--container-max-width);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--space-3);
  padding-right: var(--space-3);
}

/* Header styling */

.site-header {
  position: sticky;
  top: 0;
  z-index: 20;
  background: rgba(3, 3, 3, 0.96);
  backdrop-filter: blur(12px);
  border-bottom: 1px solid rgba(255, 255, 255, 0.04);
}

.header-inner {
  max-width: var(--container-max-width);
  margin: 0 auto;
  padding: var(--space-3) var(--space-3);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
}

.logo {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-family: var(--font-heading);
  font-size: 20px;
  font-weight: var(--font-weight-bold);
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

.logo-mark {
  padding: 4px 10px;
  border-radius: var(--radius-pill);
  background: linear-gradient(135deg, #111111, #2b2b2b);
  border: 1px solid rgba(255, 255, 255, 0.16);
}

.logo-accent {
  color: var(--color-accent-yellow);
}

.main-nav {
  flex: 1 1 auto;
}

.nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  justify-content: flex-end;
  align-items: center;
  gap: var(--space-4);
  overflow-x: auto;
}

.nav-item {
  flex: 0 0 auto;
}

.nav-link {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 6px 0;
  font-family: var(--font-heading);
  font-size: 13px;
  font-weight: var(--font-weight-medium);
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--color-neutral-100);
  opacity: 0.85;
  transition: opacity 0.18s ease-out, color 0.18s ease-out;
}

.nav-link::after {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  bottom: -6px;
  height: 2px;
  border-radius: 999px;
  background: linear-gradient(90deg, var(--color-primary-bright), var(--color-accent-red));
  transform-origin: center;
  transform: scaleX(0);
  transition: transform 0.18s ease-out;
}

.nav-link:hover {
  opacity: 1;
}

.nav-link:hover::after {
  transform: scaleX(1);
}

.nav-link--active {
  opacity: 1;
}

.nav-link--active::after {
  transform: scaleX(1);
}

/* Cart link styled as pill CTA similar to SEE ALL OFFERS */

.nav-item--cart {
  margin-left: var(--space-2);
}

.nav-link--cart {
  padding: 8px 22px;
  border-radius: var(--radius-pill);
  border: 1px solid rgba(255, 255, 255, 0.9);
  background-color: #000000;
  box-shadow: 0 0 0 1px rgba(255, 255, 255, 0.06);
  text-transform: uppercase;
  letter-spacing: 0.16em;
  font-size: 12px;
}

.nav-link--cart::after {
  display: none;
}

.nav-link--cart:hover {
  background: radial-gradient(circle at 50% 0%, rgba(0, 112, 255, 0.3) 0%, #000000 55%);
}

/* Footer styling aligned with campaign feel */

.site-footer {
  margin-top: var(--space-6);
  background: var(--gradient-footer);
  border-top: 1px solid rgba(255, 255, 255, 0.06);
  color: var(--color-neutral-100);
}

.footer-inner {
  max-width: var(--container-max-width);
  margin: 0 auto;
  padding: var(--space-6) var(--space-3) var(--space-4);
  display: flex;
  gap: var(--space-5);
  align-items: flex-start;
  justify-content: space-between;
}

.footer-brand {
  max-width: 320px;
}

.footer-logo {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-family: var(--font-heading);
  font-size: 18px;
  font-weight: var(--font-weight-bold);
  letter-spacing: 0.14em;
  text-transform: uppercase;
  margin-bottom: var(--space-2);
}

.footer-tagline {
  margin: 0;
  color: var(--color-neutral-400);
  font-size: 14px;
  line-height: var(--line-height-relaxed);
}

.footer-links {
  min-width: 220px;
}

.footer-heading {
  margin: 0 0 var(--space-2) 0;
  font-family: var(--font-heading);
  font-size: 13px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-neutral-400);
}

.footer-nav {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: var(--space-2) var(--space-4);
}

.footer-nav-item {
  font-size: 14px;
}

.footer-link {
  position: relative;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  color: var(--color-neutral-100);
  opacity: 0.8;
  transition: opacity 0.18s ease-out, transform 0.18s ease-out;
}

.footer-link::before {
  content: '';
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: radial-gradient(circle, var(--color-primary-bright) 0%, var(--color-primary) 70%);
  opacity: 0.85;
}

.footer-link:hover {
  opacity: 1;
  transform: translateX(2px);
}

.footer-bottom {
  border-top: 1px solid rgba(255, 255, 255, 0.06);
  padding: var(--space-3) var(--space-3) var(--space-4);
  text-align: center;
  font-size: 13px;
  color: var(--color-neutral-400);
}

.footer-copy {
  margin: 0;
}

/* Button system (visual reference to promo CTA and chat widget) */

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 10px 24px;
  border-radius: var(--radius-pill);
  border: none;
  font-family: var(--font-heading);
  font-size: 13px;
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  cursor: pointer;
  transition: background-color 0.18s ease-out, color 0.18s ease-out, box-shadow 0.18s ease-out, transform 0.12s ease-out;
}

.btn--primary {
  background-color: var(--color-primary);
  color: var(--color-neutral-100);
  box-shadow: var(--shadow-soft);
}

.btn--primary:hover {
  background-color: var(--color-primary-bright);
  box-shadow: var(--shadow-strong);
  transform: translateY(-1px);
}

.btn--outline-light {
  background-color: #000000;
  color: var(--color-neutral-100);
  border: 1px solid rgba(255, 255, 255, 0.9);
}

.btn--outline-light:hover {
  background: radial-gradient(circle at 50% 0%, rgba(255, 255, 255, 0.12) 0%, #000000 55%);
}

/* Responsive layout adjustments */

@media (max-width: 900px) {
  .header-inner {
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
    gap: var(--space-3);
  }

  .nav-list {
    gap: var(--space-3);
  }

  .footer-inner {
    flex-direction: column;
    align-items: flex-start;
    padding-top: var(--space-5);
    padding-bottom: var(--space-3);
  }

  .footer-nav {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 600px) {
  .header-inner {
    flex-direction: column;
    align-items: flex-start;
  }

  .main-nav {
    width: 100%;
  }

  .nav-list {
    justify-content: flex-start;
  }

  .nav-link--cart {
    padding-inline: 18px;
  }

  .footer-nav {
    grid-template-columns: 1fr;
  }
}
